```tulpar
// TCP sunucusu oluştur
int sunucu_fd = socket_server("127.0.0.1", 8080);
print("Sunucu 8080 portunda dinliyor...");

while (true) {
    // Bağlantı kabul et
    int istemci_fd = socket_accept(sunucu_fd);
    
    // Veri al
    str veri = socket_receive(istemci_fd, 1024);
    print("Alınan:", veri);
    
    // Yanıt gönder
